// Obtenemos las 200 filas que vienen del Google Sheet
const items = $input.all();

// Recorremos la lista uno por uno
for (const item of items) {
  // Añadimos datos nuevos al JSON de cada cliente
  item.json.Procesado_n8n = true;
  item.json.Etiqueta = "Revisado por JS";
  item.json.processedTimestamp = new Date().toISOString();
}

// Devolvemos el "tren" de datos con nuevas columnas
return items;

const items = $input.all();

// Usamos .filter() para crear una lista nueva. 
// Solo pasan los que tienen 18 años o más en la columna "Age".
const clientesAdultos = items.filter(item => item.json.Age >= 30);

// Si conectas un nodo de Gmail después, solo enviará emails a este grupo reducido
return clientesAdultos;

const items = $input.all();

for (const item of items) {
  // 1. Limpiamos el texto: Pasamos el género a mayúsculas
  item.json.Gender = item.json.Gender.toUpperCase();

  // 2. Cálculo matemático: Multiplicamos los miles (k$) por 1000
  const ingresoMiles = item.json["Annual Income (k$)"];
  item.json.IngresoRealDolares = ingresoMiles * 1000;
}

// Devolvemos los 200 clientes, pero ahora con los datos limpios y calculados
return items;

const items = $input.all();

let sumaIngresos = 0;
let clientesEstrella = 0;

// Recorremos los 200 clientes para acumular los datos
for (const item of items) {
  sumaIngresos = sumaIngresos + item.json["Annual Income (k$)"];

  // Contamos cuántos clientes tienen un Spending Score superior a 80
  if (item.json["Spending Score (1-100)"] > 80) {
    clientesEstrella = clientesEstrella + 1;
  }
}

// ATENCIÓN: No devolvemos "items". Devolvemos un solo objeto nuevo.
return [{
  json: {
    mensaje: "Reporte de la base de datos generado con éxito",
    total_clientes_analizados: items.length,
    ingreso_total_k: sumaIngresos,
    clientes_alto_valor: clientesEstrella
  }
}];

const items = $input.all();

let sumaIngresos = 0;
let clientesEstrella = 0;

// NUEVO: variables nuevas para el resumen
let totalMujeres = 0;
let totalHombres = 0;
let sumaEdades = 0;


for (const item of items) {
  sumaIngresos = sumaIngresos + item.json["Annual Income (k$)"];

  if (item.json["Spending Score (1-100)"] > 80) {
    clientesEstrella = clientesEstrella + 1;
  }

  // NUEVO: Contar por género usando la Pista 1 (===)
  // Usamos el "salvavidas" por si la celda está vacía
  if (item.json.Gender) {
    if (item.json.Gender === "Female") {
      totalMujeres = totalMujeres + 1;
    } 
    if (item.json.Gender === "Male") {
      totalHombres = totalHombres + 1;
    }
  }

  // NUEVO: Sumar todas las edades
  if (item.json.Age) {
    sumaEdades = sumaEdades + item.json.Age;
  }
}

// 3. Cálculos finales fuera del bucle (Pista 2: Redondeo)
const edadPromedio = Math.round(sumaEdades / items.length);

// Devolver el gran informe final
return [{
  json: {
    mensaje: "Reporte Avanzado de la base de datos",
    total_clientes_analizados: items.length,
    ingreso_total_k: sumaIngresos,
    clientes_alto_valor: clientesEstrella,
    // Añadimos los nuevos datos al JSON de salida
    total_mujeres: totalMujeres,
    total_hombres: totalHombres,
    edad_media: edadPromedio
  }
}];
